from exceptions import DivisionByZeroError, InvalidOperatorError

def calculate(num1: float, num2: float, operator: str) -> float:
    if operator == '+':
        return float(num1 + num2)
    elif operator == '-':
        return float(num1 - num2)
    elif operator == '*':
        return float(num1 * num2)
    elif operator == '/':
        if num2 == 0:
            raise DivisionByZeroError("Division by zero is not allowed.")
        return float(num1 / num2)
    else:
        raise InvalidOperatorError(f"The operator '{operator}' is not supported.")

