    items = load_all()
    for item in items:
        if item['item_id'] == item_id:
            item['quantity'] += quantity
            save_all(items)
            return

    new_item = create_item(item_id, name, quantity)
    items.append(new_item)
    save_all(items)

def remove_stock(item_id: str, quantity: int) -> bool:
    items = load_all()
    for item in items:
        if item['item_id'] == item_id:
            if item['quantity'] >= quantity:
                item['quantity'] -= quantity
                save_all(items)
                return True
            return False
    return False

def get_quantity(item_id: str) -> int:
    items = load_all()
    for item in items:
        if item['item_id'] == item_id:
            return item['quantity']
    return 0

def get_all_items() -> list[dict]:
