from models import Coupon

def calculate_discount(subtotal: float, coupon: Coupon) -> float:
    """
    Calculates the discount amount based on the coupon type and value.
    Supported discount_types: 'percentage', 'fixed_amount'.
    """
    discount = 0.0

    if coupon.discount_type == 'percentage':
        discount = subtotal * (coupon.value / 100.0)
    elif coupon.discount_type == 'fixed_amount':
        discount = coupon.value

    # Ensure discount does not exceed the subtotal
    return min(discount, subtotal)

