from models import Product, CartItem, Coupon
from inventory_manager import check_stock
from coupon_manager import calculate_discount

def calculate_cart_total(items: list[CartItem], products: dict[str, Product], coupon: Coupon | None) -> float:
    subtotal = 0.0

    for item in items:
        product = products.get(item.product_id)
        if not product:
            raise ValueError(f"Product with ID {item.product_id} not found in registry.")

        if not check_stock(item.product_id, item.quantity, products):
            raise ValueError(f"Insufficient stock for product: {product.name}")

        subtotal += product.price * item.quantity

    discount = 0.0
    if coupon:
        discount = calculate_discount(subtotal, coupon)

    total = subtotal - discount
    return max(0.0, total)

