def calculate(n1: float, n2: float, op: str) -> float:
    if op == '+':
        return float(n1 + n2)
    elif op == '-':
        return float(n1 - n2)
    elif op == '*':
        return float(n1 * n2)
    elif op == '/':
        if n2 == 0:
            raise ZeroDivisionError("Division by zero is not allowed.")
        return float(n1 / n2)
    else:
        raise ValueError(f"Unsupported operator: {op}")

