def add_memo(content: str) -> None:
    memos = load_data()
    new_id = max([m['id'] for m in memos], default=0) + 1
    memos.append({'id': new_id, 'content': content})
    save_data(memos)

def update_memo(memo_id: int, content: str) -> bool:
    memos = load_data()
    for memo in memos:
        if memo['id'] == memo_id:
            memo['content'] = content
            save_data(memos)
            return True
    return False

def remove_memo(memo_id: int) -> bool:
    memos = load_data()
    initial_count = len(memos)
    memos = [m for m in memos if m['id'] != memo_id]
    if len(memos) < initial_count:
        save_data(memos)
        return True
    return False

def fetch_all_memos() -> list[dict]:
    return load_data()

