# Mock database of available coupons
_COUPONS_DB = {
    "SAVE10": Coupon("SAVE10", "percentage", 10.0),
    "WELCOME5": Coupon("WELCOME5", "fixed", 5.0),
    "SUMMER20": Coupon("SUMMER20", "percentage", 20.0),
    "BOGO15": Coupon("BOGO15", "fixed", 15.0),
}

def calculate_discount(subtotal: float, coupon_code: str) -> float:
    """
    Validates a coupon code and calculates the discount amount based on the subtotal.
    Returns 0.0 if the coupon is invalid.
    """
    coupon = _COUPONS_DB.get(coupon_code)

    if not coupon:
        return 0.0

    discount_amount = 0.0
    if coupon.discount_type == "percentage":
        discount_amount = subtotal * (coupon.value / 100.0)
    elif coupon.discount_type == "fixed":
        discount_amount = coupon.value

    # Ensure the discount does not exceed the subtotal
    return min(discount_amount, subtotal)

