    # Generate a new ID based on the highest existing ID
    new_id = 1
    if memos:
        new_id = max(memo['id'] for memo in memos) + 1

    new_memo = {
        "id": new_id,
        "content": content
    }

    memos.append(new_memo)
    storage_handler.save_memos(memos)
    return new_memo

def update_memo(memo_id: int, new_content: str) -> bool:
    memos = storage_handler.load_memos()
    updated = False

    for memo in memos:
        if memo['id'] == memo_id:
            memo['content'] = new_content
            updated = True
            break

    if updated:
        storage_handler.save_memos(memos)

    return updated

def delete_memo(memo_id: int) -> bool:
    memos = storage_handler.load_memos()
    initial_count = len(memos)

    # Filter out the memo with the given id
    memos = [memo for memo in memos if memo['id'] != memo_id]

    if len(memos) < initial_count:
        storage_handler.save_memos(memos)
        return True

    return False

