from models import Coupon

# Mock database of available coupons
COUPON_DATABASE = {
    "SAVE10": Coupon("SAVE10", 10.0, True),
    "FLAT20": Coupon("FLAT20", 20.0, False),
    "WELCOME50": Coupon("WELCOME50", 50.0, True),
}

def calculate_discount_amount(subtotal: float, coupon_code: str) -> float:
    """
    Calculates the discount amount based on the provided subtotal and coupon code.
    Returns 0.0 if the coupon is invalid.
    """
    coupon = COUPON_DATABASE.get(coupon_code)

    if not coupon:
        return 0.0

    if coupon.is_percentage:
        discount = subtotal * (coupon.value / 100.0)
    else:
        discount = coupon.value

    # Ensure the discount does not exceed the subtotal
    return min(discount, subtotal)

