def calculate_discount(subtotal: float, coupon: dict) -> float:
    """
    Calculates the discount amount based on the coupon rules.
    Expected coupon dict structure:
    {
        'type': 'percentage' | 'fixed',
        'value': float,
        'min_spend': float
    }
    """
    if not coupon:
        return 0.0

    min_spend = coupon.get('min_spend', 0.0)
    if subtotal < min_spend:
        return 0.0

    discount_type = coupon.get('type')
    value = coupon.get('value', 0.0)

    if discount_type == 'percentage':
        discount_amount = subtotal * (value / 100.0)
    elif discount_type == 'fixed':
        discount_amount = float(value)
    else:
        discount_amount = 0.0

    # Discount cannot exceed the subtotal
    return min(discount_amount, subtotal)

