def calculate(n1: float, n2: float, operator: str) -> float:
    if operator == '+':
        return float(n1 + n2)
    elif operator == '-':
        return float(n1 - n2)
    elif operator == '*':
        return float(n1 * n2)
    elif operator == '/':
        if n2 == 0:
            raise ZeroDivisionError("Cannot divide by zero")
        return float(n1 / n2)
    else:
        raise ValueError(f"Unsupported operator: {operator}")

