def calculate_final_total(cart_items: list[CartItem], products: dict[str, Product], coupon: Coupon | None, inventory_service: InventoryService) -> float:
    subtotal = 0.0

    for item in cart_items:
        # Verify stock availability using the provided inventory service
        if not inventory_service.is_stock_available(item.product_id, item.quantity):
            raise ValueError(f"Insufficient stock for product ID: {item.product_id}")

        # Retrieve product details from the product catalog
        product = products.get(item.product_id)
        if not product:
            raise ValueError(f"Product ID {item.product_id} not found in catalog")

        subtotal += product.price * item.quantity

    discount_amount = 0.0
    if coupon:
        discount_amount = calculate_discount(subtotal, coupon)

    final_total = subtotal - discount_amount

    return max(0.0, final_total)

