# Mock database of available coupons
_COUPONS_DATABASE = {
    "SAVE10": Coupon("SAVE10", "percentage", 10.0),
    "SAVE20": Coupon("SAVE20", "percentage", 20.0),
    "FLAT5": Coupon("FLAT5", "fixed", 5.0),
    "FLAT10": Coupon("FLAT10", "fixed", 10.0),
}

def get_coupon(code: str) -> Coupon:
    """
    Retrieves a Coupon object based on the provided code.
    Returns None if the coupon is not found.
    """
    return _COUPONS_DATABASE.get(code)

def calculate_discount(subtotal: float, coupon: Coupon) -> float:
    """
    Calculates the discount amount based on the subtotal and coupon type.
    Supported discount_types: 'percentage', 'fixed'.
    """
    if not coupon:
        return 0.0

    discount_amount = 0.0
    if coupon.discount_type == "percentage":
        discount_amount = subtotal * (coupon.value / 100.0)
    elif coupon.discount_type == "fixed":
        discount_amount = coupon.value

    # Ensure discount does not exceed the subtotal
    return min(discount_amount, subtotal)

