    coupon = coupon_manager.get_coupon(code)
    if coupon:
        _active_coupon = coupon
        return True
    return False

def get_total_summary() -> dict[str, float]:
    subtotal = 0.0
    for product, quantity in _cart_items.values():
        subtotal += product.price * quantity

    discount = 0.0
    if _active_coupon:
        discount = coupon_manager.calculate_discount(subtotal, _active_coupon)

    return {
        "subtotal": subtotal,
        "discount": discount,
        "total": subtotal - discount
    }

