from storage import load_all_memos, save_all_memos

def get_all_memos() -> list[dict]:
    return load_all_memos()

def add_memo(content: str) -> dict:
    memos = load_all_memos()

    # Determine the next ID based on the current highest ID
    current_max_id = max([memo['id'] for memo in memos], default=0)
    new_id = current_max_id + 1

    new_memo = {
        'id': new_id,
        'content': content
    }

    memos.append(new_memo)
    save_all_memos(memos)
    return new_memo

def edit_memo(memo_id: int, content: str) -> bool:
    memos = load_all_memos()
    found = False

    for memo in memos:
        if memo['id'] == memo_id:
            memo['content'] = content
            found = True
            break

    if found:
        save_all_memos(memos)

    return found

def delete_memo(memo_id: int) -> bool:
    memos = load_all_memos()
    original_count = len(memos)

    memos = [memo for memo in memos if memo['id'] != memo_id]

    if len(memos) < original_count:
        save_all_memos(memos)
        return True

    return False

