from repository import get_user, save_user
from models import User

def earn_points(user_id: str, amount: int) -> bool:
    user = get_user(user_id)
    if user is None:
        user = User(user_id=user_id, balance=amount)
    else:
        user.balance += amount
    save_user(user)
    return True

def use_points(user_id: str, amount: int) -> bool:
    user = get_user(user_id)
    if user is None or user.balance < amount:
        return False
    user.balance -= amount
    save_user(user)
    return True

def get_balance(user_id: str) -> int:
    user = get_user(user_id)
    if user is None:
        return 0
    return user.balance

