ROLE_PERMISSIONS = {
    "admin": {"read", "write", "delete", "manage_users"},
    "editor": {"read", "write"},
    "viewer": {"read"},
    "guest": {"read"}
}

def is_authorized(user, action_name):
    """
    Validates if a user role is authorized for a specific action.

    :param user: Dictionary containing user details {"name": str, "role": str}
    :param action_name: The name of the action to validate
    :return: True if authorized, False otherwise
    """
    role = user.get("role")
    if not role:
        return False

    allowed_actions = ROLE_PERMISSIONS.get(role, set())
    return action_name in allowed_actions

