import models
import permission_engine
import actions

def run_demo():
    # Create users with different roles
    admin = models.create_user("Alice", "admin")
    standard_user = models.create_user("Bob", "user")
    guest_user = models.create_user("Charlie", "guest")

    users = [admin, standard_user, guest_user]

    # Map action names to the actual functions in actions.py
    action_map = {
        "admin_task": actions.admin_task,
        "user_task": actions.user_task,
        "guest_task": actions.guest_task,
    }

    for user in users:
        print(f"--- Testing permissions for {user['name']} (Role: {user['role']}) ---")
        for action_name, action_func in action_map.items():
            if permission_engine.is_authorized(user, action_name):
                result = action_func()
                print(f"SUCCESS: {user['name']} executed {action_name}: {result}")
            else:
                print(f"DENIED: {user['name']} is not authorized to perform {action_name}")
        print()

if __name__ == "__main__":
    run_demo()

