from models import create_cart_item

def add_item(cart, product, quantity, inventory_manager):
    product_id = product.get('id')
    if inventory_manager.check_stock(product_id, quantity):
        item = create_cart_item(product, quantity)
        cart.append(item)
        return True
    return False

def get_cart_summary(cart, coupon, inventory_manager, coupon_engine):
    subtotal = 0.0
    for item in cart:
        price = item['product'].get('price', 0.0)
        quantity = item.get('quantity', 0)
        subtotal += price * quantity

    discount = 0.0
    if coupon:
        discount = coupon_engine.calculate_discount(subtotal, coupon)

    total = subtotal - discount
    return {
        'subtotal': subtotal,
        'discount': discount,
        'total': total
    }
